import React, { useState, useEffect } from 'react';
import { cities, places, trips } from '../utils/api';
import { useAuth } from '../utils/AuthContext';

const AllPlaces = () => {
  const { user } = useAuth();
  const [cityList, setCityList] = useState([]);
  const [allPlaces, setAllPlaces] = useState([]);
  const [selectedCity, setSelectedCity] = useState('ALL');
  const [selectedType, setSelectedType] = useState('ALL');
  const [filteredPlaces, setFilteredPlaces] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedPlace, setSelectedPlace] = useState(null);
  const [tripName, setTripName] = useState('');
  const [budget, setBudget] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [savedItineraries, setSavedItineraries] = useState([]);
  const [selectedItinerary, setSelectedItinerary] = useState('new');
  const [showRatingModal, setShowRatingModal] = useState(false);
  const [ratingPlace, setRatingPlace] = useState(null);
  const [userRating, setUserRating] = useState(0);
  const [showMapModal, setShowMapModal] = useState(false);
  const [mapPlace, setMapPlace] = useState(null);

  useEffect(() => {
    fetchCities();
    fetchAllPlaces();
    loadSavedItineraries();
  }, []);

  useEffect(() => {
    filterPlaces();
  }, [allPlaces, selectedCity, selectedType]);

  const fetchCities = async () => {
    try {
      const response = await cities.getAll();
      setCityList(response.data);
    } catch (error) {
      console.error('Failed to fetch cities:', error);
    }
  };

  const fetchAllPlaces = async () => {
    try {
      const response = await cities.getAll();
      const allCityPlaces = [];

      for (const city of response.data) {
        try {
          const placesResponse = await places.getByCity(city.id);
          const placesWithCity = placesResponse.data.map(place => ({
            ...place,
            city_name: city.name
          }));
          allCityPlaces.push(...placesWithCity);
        } catch (error) {
          console.error(`Failed to fetch places for ${city.name}:`, error);
        }
      }

      setAllPlaces(allCityPlaces);
    } catch (error) {
      console.error('Failed to fetch places:', error);
    }
  };

  const filterPlaces = () => {
    let filtered = allPlaces;

    if (selectedCity !== 'ALL') {
      filtered = filtered.filter(place => place.city_id == selectedCity);
    }

    if (selectedType !== 'ALL') {
      filtered = filtered.filter(place => place.type === selectedType);
    }

    setFilteredPlaces(filtered);
  };

  const getTypeColor = (type) => {
    switch (type) {
      case 'HOTEL': return '#3b82f6';
      case 'RESTAURANT': return '#ef4444';
      case 'ATTRACTION': return '#10b981';
      default: return '#6b7280';
    }
  };

  const loadSavedItineraries = () => {
    const saved = JSON.parse(localStorage.getItem('savedItineraries') || '[]');
    setSavedItineraries(saved);
  };

  const handleAddToTrip = (place) => {
    setSelectedPlace(place);
    setShowModal(true);
    setTripName('');
    setBudget('');
    setStartDate('');
    setEndDate('');
    setSelectedItinerary('new');
  };

  const handleRatePlace = (place) => {
    setRatingPlace(place);
    setUserRating(0);
    setShowRatingModal(true);
  };

  const handleViewOnMap = (place) => {
    setMapPlace(place);
    setShowMapModal(true);
  };

  const submitRating = () => {
    if (userRating === 0) {
      alert('Please select a rating');
      return;
    }

    // Store rating in localStorage with user ID
    const ratings = JSON.parse(localStorage.getItem('placeRatings') || '{}');
    const userKey = `user_${user.id}`;
    if (!ratings[userKey]) {
      ratings[userKey] = {};
    }
    ratings[userKey][ratingPlace.id] = userRating;
    localStorage.setItem('placeRatings', JSON.stringify(ratings));

    alert(`Thank you for rating ${ratingPlace.name}!`);
    setShowRatingModal(false);
    setRatingPlace(null);
    setUserRating(0);

    // Force re-render to update overall rating
    setFilteredPlaces([...filteredPlaces]);
  };

  const getUserRating = (placeId) => {
    const ratings = JSON.parse(localStorage.getItem('placeRatings') || '{}');
    const userKey = `user_${user.id}`;
    return ratings[userKey]?.[placeId] || 0;
  };

  const getOverallRating = (place) => {
    const ratings = JSON.parse(localStorage.getItem('placeRatings') || '{}');
    const allRatings = [];

    // Collect all user ratings for this place
    Object.keys(ratings).forEach(userKey => {
      if (ratings[userKey][place.id]) {
        allRatings.push(ratings[userKey][place.id]);
      }
    });

    if (allRatings.length === 0) {
      return place.rating; // Return original rating if no user ratings
    }

    // Calculate average of user ratings
    const average = allRatings.reduce((sum, rating) => sum + rating, 0) / allRatings.length;
    return average.toFixed(1);
  };

  const handleSaveToTrip = () => {
    if (selectedItinerary === 'new') {
      if (!tripName.trim()) {
        alert('Please enter a trip name');
        return;
      }
      if (!budget || parseFloat(budget) <= 0) {
        alert('Please enter a valid budget');
        return;
      }
      if (!startDate) {
        alert('Please select a start date');
        return;
      }
      if (!endDate) {
        alert('Please select an end date');
        return;
      }
      if (new Date(endDate) <= new Date(startDate)) {
        alert('End date must be after start date');
        return;
      }

      const days = Math.ceil((new Date(endDate) - new Date(startDate)) / (1000 * 60 * 60 * 24)) + 1;

      const newTrip = {
        id: Date.now(),
        tripName: tripName.trim(),
        city: selectedPlace.city_name,
        budget: parseFloat(budget),
        startDate,
        endDate,
        days,
        places: [selectedPlace],
        totalCost: parseFloat(selectedPlace.price),
        createdAt: new Date().toISOString()
      };

      const updated = [...savedItineraries, newTrip];
      setSavedItineraries(updated);
      localStorage.setItem('savedItineraries', JSON.stringify(updated));
      alert(`New trip "${tripName}" created with ${selectedPlace.name}!`);
    } else {
      const tripIndex = savedItineraries.findIndex(trip => trip.id == selectedItinerary);
      if (tripIndex !== -1) {
        const trip = savedItineraries[tripIndex];
        const exists = trip.places.find(p => p.id === selectedPlace.id);

        if (!exists) {
          trip.places.push(selectedPlace);
          trip.totalCost += parseFloat(selectedPlace.price);

          const updated = [...savedItineraries];
          updated[tripIndex] = trip;
          setSavedItineraries(updated);
          localStorage.setItem('savedItineraries', JSON.stringify(updated));
          alert(`${selectedPlace.name} added to "${trip.tripName}"!`);
        } else {
          alert(`${selectedPlace.name} is already in "${trip.tripName}"!`);
        }
      }
    }

    setShowModal(false);
    setSelectedPlace(null);
    setTripName('');
    setBudget('');
    setStartDate('');
    setEndDate('');
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>Explore Places</h1>
        <div style={styles.filters}>
          <select 
            value={selectedCity} 
            onChange={(e) => setSelectedCity(e.target.value)}
            style={styles.filterSelect}
          >
            <option value="ALL">All Cities</option>
            {cityList.map(city => (
              <option key={city.id} value={city.id}>{city.name}</option>
            ))}
          </select>
          <select 
            value={selectedType} 
            onChange={(e) => setSelectedType(e.target.value)}
            style={styles.filterSelect}
          >
            <option value="ALL">All Types</option>
            <option value="HOTEL">Hotels</option>
            <option value="RESTAURANT">Restaurants</option>
            <option value="ATTRACTION">Attractions</option>
          </select>
        </div>
      </div>

      <div style={styles.placesGrid}>
        {filteredPlaces.map(place => (
          <div key={place.id} style={styles.placeCard}>
            <div style={styles.imageContainer}>
              {place.image_url ? (
                <img 
                  src={`http://localhost:5000${place.image_url}`} 
                  alt={place.name}
                  style={styles.placeImage}
                />
              ) : (
                <div style={styles.imagePlaceholder}>
                  📷
                </div>
              )}
            </div>
            <div style={styles.cardContent}>
              <div style={styles.cardHeader}>
                <h3 style={styles.placeName}>{place.name}</h3>
                <span style={{...styles.typeTag, backgroundColor: getTypeColor(place.type)}}>
                  {place.type}
                </span>
              </div>
              <p style={styles.cityName}>{place.city_name}</p>
              {place.description && (
                <p style={styles.description}>{place.description}</p>
              )}
              <div style={styles.cardFooter}>
                <div style={styles.price}>NPR {place.price}</div>
                <div style={styles.rating}>★ {getOverallRating(place)}</div>
                {getUserRating(place.id) > 0 && (
                  <div style={styles.userRating}>Your: {getUserRating(place.id)}★</div>
                )}
              </div>
              <div style={styles.buttonGroup}>
                <button 
                  onClick={() => handleAddToTrip(place)}
                  style={styles.addButton}
                >
                  Add to Trip
                </button>
                <button 
                  onClick={() => handleRatePlace(place)}
                  style={styles.rateButton}
                >
                  Rate Place
                </button>
                <button 
                  onClick={() => handleViewOnMap(place)}
                  style={styles.mapButton}
                >
                  View on Map
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredPlaces.length === 0 && (
        <div style={styles.noResults}>
          <h3>No places found</h3>
          <p>Try adjusting your filters to see more results.</p>
        </div>
      )}

      {showModal && (
        <div style={styles.modal}>
          <div style={styles.modalContent}>
            <h3>Add {selectedPlace?.name} to Trip</h3>

            <div style={{marginBottom: '1rem'}}>
              <label style={{display: 'block', marginBottom: '0.5rem', fontWeight: '600'}}>Choose Option:</label>
              <select 
                value={selectedItinerary} 
                onChange={(e) => setSelectedItinerary(e.target.value)}
                style={styles.input}
              >
                <option value="new">Create New Trip</option>
                {savedItineraries.map(trip => (
                  <option key={trip.id} value={trip.id}>{trip.tripName}</option>
                ))}
              </select>
            </div>

            {selectedItinerary === 'new' && (
              <>
                <div style={{marginBottom: '1rem'}}>
                  <label style={{display: 'block', marginBottom: '0.5rem', fontWeight: '600'}}>Trip Name:</label>
                  <input
                    type="text"
                    value={tripName}
                    onChange={(e) => setTripName(e.target.value)}
                    placeholder="Enter trip name..."
                    style={styles.input}
                  />
                </div>

                <div style={{marginBottom: '1rem'}}>
                  <label style={{display: 'block', marginBottom: '0.5rem', fontWeight: '600'}}>Budget (NPR):</label>
                  <input
                    type="number"
                    value={budget}
                    onChange={(e) => setBudget(e.target.value)}
                    placeholder="Enter budget..."
                    style={styles.input}
                    min="0"
                  />
                </div>

                <div style={{display: 'flex', gap: '1rem', marginBottom: '1rem'}}>
                  <div style={{flex: 1}}>
                    <label style={{display: 'block', marginBottom: '0.5rem', fontWeight: '600'}}>Start Date:</label>
                    <input
                      type="date"
                      value={startDate}
                      onChange={(e) => setStartDate(e.target.value)}
                      style={styles.input}
                    />
                  </div>
                  <div style={{flex: 1}}>
                    <label style={{display: 'block', marginBottom: '0.5rem', fontWeight: '600'}}>End Date:</label>
                    <input
                      type="date"
                      value={endDate}
                      onChange={(e) => setEndDate(e.target.value)}
                      style={styles.input}
                    />
                  </div>
                </div>
              </>
            )}

            <div style={styles.modalActions}>
              <button onClick={handleSaveToTrip} style={styles.saveButton}>
                {selectedItinerary === 'new' ? 'Create Trip' : 'Add to Trip'}
              </button>
              <button onClick={() => setShowModal(false)} style={styles.cancelButton}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      {showRatingModal && (
        <div style={styles.modal}>
          <div style={styles.modalContent}>
            <h3>Rate {ratingPlace?.name}</h3>

            <div style={{marginBottom: '1rem', textAlign: 'center'}}>
              <p>How would you rate this place?</p>
              <div style={styles.starRating}>
                {[1, 2, 3, 4, 5].map(star => (
                  <span
                    key={star}
                    onClick={() => setUserRating(star)}
                    style={{
                      ...styles.star,
                      color: star <= userRating ? '#f59e0b' : '#d1d5db'
                    }}
                  >
                    ★
                  </span>
                ))}
              </div>
            </div>

            <div style={styles.modalActions}>
              <button onClick={submitRating} style={styles.saveButton}>
                Submit Rating
              </button>
              <button onClick={() => setShowRatingModal(false)} style={styles.cancelButton}>
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

